<?php
namespace App\Controllers;
use App\Config\Database;use App\Helpers\{Auth,Csrf,Flash};
final class MusicController {public function play(int $id):void{Auth::requireLogin();Csrf::verify();$db=Database::connection();$u=Auth::user();if($u['tipo_usuario']==='free'){$s=$db->prepare("SELECT COUNT(*) FROM reproducciones WHERE usuario_id=? AND YEAR(fecha_hora)=YEAR(CURDATE()) AND MONTH(fecha_hora)=MONTH(CURDATE())");$s->execute([Auth::id()]);$limit=(require dirname(__DIR__,2).'/config.php')['free_monthly_limit'];if((int)$s->fetchColumn()>=$limit){Flash::set('error','Alcanzó el límite mensual gratuito. Adquiera Premium.');Auth::go('/mi-cuenta');}}$s=$db->prepare("INSERT INTO reproducciones(cancion_id,usuario_id,nacionalidad_usuario) VALUES(?,?,?)");$s->execute([$id,Auth::id(),$u['nacionalidad']]);Flash::set('success','Reproducción registrada.');Auth::go('/#canciones');} public function favorite(int $id):void{Auth::requireLogin();Csrf::verify();$db=Database::connection();$s=$db->prepare("SELECT 1 FROM favoritos WHERE usuario_id=? AND cancion_id=?");$s->execute([Auth::id(),$id]);if($s->fetchColumn()){$db->prepare("DELETE FROM favoritos WHERE usuario_id=? AND cancion_id=?")->execute([Auth::id(),$id]);}else{$db->prepare("INSERT INTO favoritos(usuario_id,cancion_id) VALUES(?,?)")->execute([Auth::id(),$id]);}Auth::go('/mi-cuenta');}}
